from abc import ABC, abstractmethod  # ABC = Abstract Base Class

class PaymentProcessor(ABC):
    # This is an abstract class — it cannot be instantiated directly
    # It defines the contract that all payment methods must follow

    @abstractmethod  # Decorator marking this as mandatory for subclasses
    def process_payment(self, amount):
        # No implementation — subclasses MUST override this
        pass  # pass is a placeholder meaning "do nothing"

    @abstractmethod
    def refund(self, transaction_id):
        pass

class CreditCardProcessor(PaymentProcessor):
    # Must implement ALL abstract methods from PaymentProcessor
    def process_payment(self, amount):
        # Real implementation would call a credit card API here
        return f"Charged ${amount} to credit card"

    def refund(self, transaction_id):
        return f"Refunded transaction {transaction_id}"

class PayPalProcessor(PaymentProcessor):
    def process_payment(self, amount):
        return f"Charged ${amount} via PayPal"

    def refund(self, transaction_id):
        return f"Refunded PayPal transaction {transaction_id}"

# Both processors can be used interchangeably — that's the power of abstraction
processors = [CreditCardProcessor(), PayPalProcessor()]
for p in processors:
    print(p.process_payment(50))
# Expected output:
# Charged $50 to credit card
# Charged $50 via PayPal
